const input = $input.first().json;
const data = input.body || {};

// Construction du texte affiché (max 32 caractères)
const display = `${data.contact_name || 'Client'} - ${data.motif || ''}`
  .trim()
  .substring(0, 32);

// Résultat
return [
  {
    json: {
      caller_id: data.caller_id || '',
      display_name: display,
      contact_name: data.contact_name || 'Client',
      motif: data.motif || '',
      urgence: data.urgence || false,
      adresse: data.adresse || '',
    },
  },
];

const net = require('net');

const AMI_HOST = 'freepbx';
const AMI_PORT = 5038;
const AMI_USER = 'n8n';
const AMI_PASS = 'YOUR_AMI_PASSWORD';

const input = $input.first().json;

return new Promise((resolve, reject) => {
  const client = new net.Socket();

  let buffer = '';
  let loggedIn = false;
  let step = 0;

  client.connect(AMI_PORT, AMI_HOST, () => {
    const loginAction =
      `Action: Login\r\n` +
      `Username: ${AMI_USER}\r\n` +
      `Secret: ${AMI_PASS}\r\n\r\n`;

    client.write(loginAction);
  });

  client.on('data', (dataIn) => {
    buffer += dataIn.toString();

    // Étape 1 — Auth OK → Originate avec CallerID personnalisé
    if (!loggedIn && buffer.includes('Authentication accepted')) {
      loggedIn = true;
      step = 1;

      const originateAction =
        `Action: Originate\r\n` +
        `Channel: SIP/100\r\n` +
        `Exten: ${input.caller_id}\r\n` +
        `Context: from-trunk\r\n` +
        `Priority: 1\r\n` +
        `CallerID: "${input.display_name}" <${input.caller_id}>\r\n` +
        `Variable: MOTIF=${input.motif || ''},URGENCE=${input.urgence || ''},ADRESSE=${input.adresse || ''}\r\n` +
        `Timeout: 30000\r\n` +
        `Async: true\r\n\r\n`;

      client.write(originateAction);
    }

    // Succès → fermeture propre
    if (step === 1 && buffer.includes('Response: Success')) {
      client.write('Action: Logoff\r\n\r\n');
      client.destroy();

      resolve([
        {
          json: {
            success: true,
            display: input.display_name,
          },
        },
      ]);
    }

    // Erreur AMI
    if (buffer.includes('Response: Error')) {
      client.destroy();
      reject(new Error(`AMI error: ${buffer}`));
    }
  });

  client.on('error', (err) => {
    client.destroy();
    reject(err);
  });

  // Timeout de sécurité
  setTimeout(() => {
    client.destroy();
    reject(new Error('AMI timeout'));
  }, 10000);
});
